mapper.select:
SELECT c.id, c.name, c.description, c.avatar, c.owner_id as ownerId, c.type, c.status, c.create_time as createTime, c.update_time as updateTime, u.nickname as ownerNickname, u.avatar as ownerAvatar, COUNT(cm.id) as memberCount FROM circle c LEFT JOIN users u ON c.owner_id = u.id LEFT JOIN circle_member cm ON c.id = cm.circle_id AND cm.status = #{T(com.gcs.enums.CommonStatus).ENABLED.code} WHERE c.status = #{T(com.gcs.enums.CommonStatus).ENABLED.code}
${ew.sqlSegment}
GROUP BY c.id, u.nickname, u.avatar

